CREATE DATABASE IF NOT EXISTS giavico_inventory CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE giavico_inventory;

CREATE TABLE IF NOT EXISTS inventory_categories (
  id BIGINT PRIMARY KEY AUTO_INCREMENT,
  name VARCHAR(120) NOT NULL UNIQUE,
  description VARCHAR(500) NOT NULL,
  created_by VARCHAR(120) NOT NULL,
  status VARCHAR(24) NOT NULL,
  created_on DATE NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS inventory_products (
  id BIGINT PRIMARY KEY AUTO_INCREMENT,
  source_sequence INT NULL,
  sku VARCHAR(16) NOT NULL UNIQUE,
  name VARCHAR(255) NOT NULL,
  category VARCHAR(120) NOT NULL,
  brand VARCHAR(120) NOT NULL,
  warehouse VARCHAR(40) NOT NULL,
  qty INT NOT NULL,
  reorder_level INT NOT NULL,
  status VARCHAR(24) NOT NULL,
  avatar VARCHAR(500) NOT NULL,
  last_updated DATE NOT NULL,
  expired_date DATE NOT NULL,
  manufactured_date DATE NOT NULL,
  code_sheet_version VARCHAR(16) NOT NULL,
  CONSTRAINT fk_inventory_products_category FOREIGN KEY (category) REFERENCES inventory_categories(name)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

TRUNCATE TABLE inventory_products;
DELETE FROM inventory_categories;

